import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G08 區域銷售與地緣 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G08_區域銷售與地緣.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G08_區域銷售與地緣.md"}'),o={name:"審計報告庫/經營審計/6239_力成/20260617/G08_區域銷售與地緣.md"};function i(n,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="g08-區域銷售與地緣-—-力成科技-6239" tabindex="-1">G08 區域銷售與地緣 — 力成科技 (6239) <a class="header-anchor" href="#g08-區域銷售與地緣-—-力成科技-6239" aria-label="Permalink to &quot;G08 區域銷售與地緣 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>評估力成科技的區域銷售結構、生產據點的地緣政治風險，以及供應鏈韌性。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>營收以台灣為核心，產據橫跨台日中美四地。最大地緣風險為美中科技管制升級及美國廠成本壓力。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>營收以台灣為核心。台日中美四地生產：新竹總部、日本秋田（車用）、中國（僅營運點）、亞利桑那（2026Q3投產）。地緣風險：美中管制升級、美國廠成本為台灣3-4倍。本土採購率85%，LTA覆蓋60%產能，韌性中上。（數據來源：PitchBook、CMoney、FT）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、生產據點布局</strong></p><ul><li><strong>台灣</strong>：新竹3座12吋廠，研發與FOPLP先進封裝基地，2025年購入友達廠擴容</li><li><strong>日本秋田</strong>：2017年收購美光廠，專攻車用電子（ASIL-D認證），深耕Toyota供應鏈</li><li><strong>中國</strong>：2024年出售西安廠給美光，僅保留營運據點</li><li><strong>美國亞利桑那</strong>：預計2026Q3投產，鎖定NVIDIA等AI客戶</li></ul><p><strong>二、地緣風險矩陣</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">風險類別</th><th style="text-align:left;">影響程度</th><th style="text-align:left;">應對措施</th></tr></thead><tbody><tr><td style="text-align:left;">美中科技戰</td><td style="text-align:left;">中高</td><td style="text-align:left;">台日美三重產能備援，降低中國依賴</td></tr><tr><td style="text-align:left;">兩岸情勢</td><td style="text-align:left;">中</td><td style="text-align:left;">核心研發/生產留在台灣，無法完全分散</td></tr><tr><td style="text-align:left;">AI晶片出口管制</td><td style="text-align:left;">中</td><td style="text-align:left;">主要客戶為美日系，衝擊有限</td></tr><tr><td style="text-align:left;">美國廠成本</td><td style="text-align:left;">高</td><td style="text-align:left;">鎖定高毛利AI晶片以吸收成本</td></tr><tr><td style="text-align:left;">關稅/貿易壁壘</td><td style="text-align:left;">中低</td><td style="text-align:left;">在地化生產（美/日廠）降低關稅衝擊</td></tr></tbody></table><p><strong>三、供應鏈韌性評估</strong> 力成本土化採購率達85%，關鍵封裝材料（如基板、導線架、封裝膠）在台灣均有供應商。設備方面，測試機台（Advantest、Teradyne）、封裝設備（Disco、Towa）等以日系為主，同時評估美系設備備援。產能方面，LTA覆蓋60%以上產能，客戶預付30%訂金鎖定產線，大幅降低需求波動風險。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>美國廠營運成本大幅攀升</strong>：亞利桑那廠初期建設與營運成本預估為台灣同規模廠房的3-4倍，且美國半導體工程師嚴重短缺。若AI晶片需求放緩或訂單不如預期，該廠將成為獲利拖累而非成長引擎。</li><li><strong>兩岸地緣政治的不確定性</strong>：力成核心產能100%位於台灣（新竹總部），雖然已分散至日本和美國，但主要先進封裝（FOPLP）研發與量產仍在台灣。一旦台海情勢緊張，整體營運將面臨系統性風險。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>分散布局強化供應鏈韌性</strong>：台日美三角產能布局使力成能靈活應對區域性風險。日本廠服務車用客戶（ASIL-D認證）、美國廠服務AI客戶、台灣廠服務記憶體與邏輯客戶，三個基地各有專攻且互為備援，形成堅實的供應鏈護城河。</li><li><strong>美國廠可望受惠晶片法案</strong>：預計2026年Q3投產的亞利桑那廠，若取得美國晶片法案補助，可大幅降低建廠成本。同時，美系客戶（如NVIDIA、AMD）為確保供應鏈安全，傾向優先與在美設廠的封測業者合作，可望為力成帶來更多AI晶片封測訂單。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：力成 6239 區域銷售 地緣風險 日本 中國 美國（PitchBook、FT、SCMP、Asia Times）</li><li>tavily_search：力成 6239 FOPLP（工商時報、中央社、Yahoo財經）</li><li>web_search：力成 6239 法說會（Fugle、vocus分析）</li></ul>',20)])])}const f=e(o,[["render",i]]);export{c as __pageData,f as default};
